import{_ as t,o as r,c as a,ag as i}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Weekly Summaries","description":"","frontmatter":{},"headers":[],"relativePath":"features/weekly-summaries.md","filePath":"features/weekly-summaries.md"}'),o={name:"features/weekly-summaries.md"};function n(s,e,l,d,c,h){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="weekly-summaries" tabindex="-1">Weekly Summaries <a class="header-anchor" href="#weekly-summaries" aria-label="Permalink to &quot;Weekly Summaries&quot;">​</a></h1><p>SendGrail can send a scheduled weekly email report summarizing your site&#39;s email delivery performance. This provides a regular check-in without requiring you to log into the WordPress dashboard.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Weekly summaries are managed through the following settings:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>enable_weekly_summary</code></td><td>Disabled</td><td>Toggle weekly summary emails on or off</td></tr><tr><td><code>weekly_summary_day</code></td><td>Monday</td><td>Day of the week to send the report (Monday through Sunday)</td></tr><tr><td><code>weekly_summary_email</code></td><td>Site admin email</td><td>The recipient address for the summary</td></tr></tbody></table><p>The summary is sent at <strong>9:00 AM UTC</strong> on the configured day via the <code>sendgrail_weekly_summary</code> WordPress cron event.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The cron schedule depends on WordPress cron being triggered by site traffic. On low-traffic sites, the summary may be delayed. Consider using a system-level cron job to trigger <code>wp-cron.php</code> on schedule for consistent delivery timing.</p></div><h2 id="email-contents" tabindex="-1">Email Contents <a class="header-anchor" href="#email-contents" aria-label="Permalink to &quot;Email Contents&quot;">​</a></h2><p>The weekly summary email includes the following sections:</p><h3 id="stats-grid" tabindex="-1">Stats Grid <a class="header-anchor" href="#stats-grid" aria-label="Permalink to &quot;Stats Grid&quot;">​</a></h3><p>A top-level overview of the week&#39;s performance:</p><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th></tr></thead><tbody><tr><td><strong>Sent</strong></td><td>Total emails successfully delivered</td></tr><tr><td><strong>Failed</strong></td><td>Total delivery failures</td></tr><tr><td><strong>Success Rate</strong></td><td>Percentage of successful deliveries</td></tr><tr><td><strong>Open Rate</strong></td><td>Percentage of delivered emails that were opened</td></tr></tbody></table><p>Each metric includes a <strong>trend indicator</strong> comparing the current week to the previous week, so you can quickly spot improvements or regressions.</p><h3 id="per-connection-breakdown" tabindex="-1">Per-Connection Breakdown <a class="header-anchor" href="#per-connection-breakdown" aria-label="Permalink to &quot;Per-Connection Breakdown&quot;">​</a></h3><p>A table listing each SMTP connection with its individual performance for the week:</p><ul><li>Connection name</li><li>Provider</li><li>Emails sent</li><li>Emails failed</li><li>Delivery rate</li></ul><p>This helps identify whether a specific connection is underperforming relative to others.</p><h3 id="recent-failures" tabindex="-1">Recent Failures <a class="header-anchor" href="#recent-failures" aria-label="Permalink to &quot;Recent Failures&quot;">​</a></h3><p>A list of notable delivery failures from the past week, including the recipient, subject, error message, and timestamp. This section surfaces issues that may need attention without requiring you to open the full email log.</p><h2 id="delivery-method" tabindex="-1">Delivery Method <a class="header-anchor" href="#delivery-method" aria-label="Permalink to &quot;Delivery Method&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Weekly summaries are sent using the WordPress default mail function with SendGrail hooks <strong>temporarily removed</strong>. This prevents the summary from being routed through your SMTP connections, logged, or processed by open/click tracking.</p></div><p>This approach avoids:</p><ul><li><strong>Recursion</strong> -- The summary itself being logged and counted in next week&#39;s summary</li><li><strong>Tracking artifacts</strong> -- Open and click tracking pixels being injected into the report email</li><li><strong>Routing interference</strong> -- The summary being routed through a connection that may be experiencing issues</li></ul><h2 id="footer" tabindex="-1">Footer <a class="header-anchor" href="#footer" aria-label="Permalink to &quot;Footer&quot;">​</a></h2><p>Each weekly summary email includes a footer note explaining how to disable the reports. Recipients can turn off summaries directly from the SendGrail settings page without needing to locate the setting independently.</p>',25)])])}const p=t(o,[["render",n]]);export{u as __pageData,p as default};
